   402	func AddFileInfoToError(err error, fi FileMetaInfo, fs afero.Fs) error {
   403		if err == nil {
   404			return nil
   405		}
   406	
   407		meta := fi.Meta()
   408		filename := meta.Filename
   409	
   410		// Check if it's already added.
   411		for _, ferr := range herrors.UnwrapFileErrors(err) {
   412			pos := ferr.Position()
   413			errfilename := pos.Filename
   414			if errfilename == "" {
   415				pos.Filename = filename
   416				ferr.UpdatePosition(pos)
   417			}
   418	
   419			if errfilename == "" || errfilename == filename {
   420				if filename != "" && ferr.ErrorContext() == nil {
   421					f, ioerr := fs.Open(filename)
   422					if ioerr != nil {
   423						return err
   424					}
   425					defer f.Close()
   426					ferr.UpdateContent(f, nil)
   427				}
   428				return err
   429			}
   430		}
   431	
   432		lineMatcher := herrors.NopLineMatcher
   433	
   434		if textSegmentErr, ok := err.(*herrors.TextSegmentError); ok {
   435			lineMatcher = herrors.ContainsMatcher(textSegmentErr.Segment)
   436		}
   437	
   438		return herrors.NewFileErrorFromFile(err, filename, fs, lineMatcher)
