   309	func (rfs *RootMappingFs) collectDirEntries(prefix string) ([]iofs.DirEntry, error) {
   310		prefix = filepathSeparator + rfs.cleanName(prefix)
   311	
   312		var fis []iofs.DirEntry
   313	
   314		seen := make(map[string]bool) // Prevent duplicate directories
   315		level := strings.Count(prefix, filepathSeparator)
   316	
   317		collectDir := func(rm *RootMapping, fi FileMetaInfo) error {
   318			f, err := fi.Meta().Open()
   319			if err != nil {
   320				return err
   321			}
   322			direntries, err := f.(iofs.ReadDirFile).ReadDir(-1)
   323			if err != nil {
   324				f.Close()
   325				return err
   326			}
   327	
   328			for _, fi := range direntries {
   329	
   330				meta := fi.(FileMetaInfo).Meta()
   331				meta.Merge(rm.Meta)
   332	
   333				if !rm.Meta.InclusionFilter.Match(strings.TrimPrefix(meta.Filename, meta.SourceRoot), fi.IsDir()) {
   334					continue
   335				}
   336	
   337				if fi.IsDir() {
   338					name := fi.Name()
   339					if seen[name] {
   340						continue
   341					}
   342					seen[name] = true
   343					opener := func() (afero.File, error) {
   344						return rfs.Open(filepath.Join(rm.From, name))
   345					}
   346					fi = newDirNameOnlyFileInfo(name, meta, opener)
   347				} else if rm.Meta.Rename != nil {
   348					n, ok := rm.Meta.Rename(fi.Name(), true)
   349					if !ok {
   350						continue
   351					}
   352					fi.(MetaProvider).Meta().Name = n
   353				}
   354				fis = append(fis, fi)
   355			}
   356	
   357			f.Close()
   358	
   359			return nil
   360		}
   361	
   362		// First add any real files/directories.
   363		rms := rfs.getRoot(prefix)
   364		for _, rm := range rms {
   365			if err := collectDir(rm, rm.fi); err != nil {
   366				return nil, err
   367			}
   368		}
   369	
   370		// Next add any file mounts inside the given directory.
   371		prefixInside := prefix + filepathSeparator
   372		var walkFn radix.WalkFn[[]*RootMapping] = func(s string, rms []*RootMapping) (radix.WalkFlag, []*RootMapping, error) {
   373			if (strings.Count(s, filepathSeparator) - level) != 1 {
   374				// This directory is not part of the current, but we
   375				// need to include the first name part to make it
   376				// navigable.
   377				path := strings.TrimPrefix(s, prefixInside)
   378				parts := strings.Split(path, filepathSeparator)
   379				name := parts[0]
   380	
   381				if seen[name] {
   382					return radix.WalkContinue, nil, nil
   383				}
   384				seen[name] = true
   385				opener := func() (afero.File, error) {
   386					return rfs.Open(path)
   387				}
   388	
   389				fi := newDirNameOnlyFileInfo(name, nil, opener)
   390				fis = append(fis, fi)
   391	
   392				return radix.WalkContinue, nil, nil
   393			}
   394	
   395			for _, rm := range rms {
   396				name := filepath.Base(rm.From)
   397				if seen[name] {
   398					continue
   399				}
   400				seen[name] = true
   401				opener := func() (afero.File, error) {
   402					return rfs.Open(rm.From)
   403				}
   404				fi := newDirNameOnlyFileInfo(name, rm.Meta, opener)
   405				fis = append(fis, fi)
   406			}
   407	
   408			return radix.WalkContinue, nil, nil
   409		}
   410		rfs.rootMapToReal.WalkPrefix(prefixInside, walkFn)
   411	
   412		// Finally add any ancestor dirs with files in this directory.
   413		ancestors := rfs.getAncestors(prefix)
   414		for _, root := range ancestors {
   415			subdir := strings.TrimPrefix(prefix, root.key)
   416			for _, rm := range root.roots {
   417				if rm.fi.IsDir() {
   418					fi, err := rm.fi.Meta().JoinStat(subdir)
   419					if err == nil {
   420						if err := collectDir(rm, fi); err != nil {
   421							return nil, err
   422						}
   423					}
   424				}
   425			}
   426		}
   427	
   428		return fis, nil
   429	}
