   453	func (fs *RootMappingFs) doDoStat(name string) ([]FileMetaInfo, error) {
   454		name = fs.cleanName(name)
   455		key := filepathSeparator + name
   456	
   457		roots := fs.getRoot(key)
   458	
   459		if roots == nil {
   460			if fs.hasPrefix(key) {
   461				// We have directories mounted below this.
   462				// Make it look like a directory.
   463				return []FileMetaInfo{newDirNameOnlyFileInfo(name, nil, fs.virtualDirOpener(name))}, nil
   464			}
   465	
   466			// Find any real directories with this key.
   467			_, roots := fs.getRoots(key)
   468			if roots == nil {
   469				return nil, &os.PathError{Op: "LStat", Path: name, Err: os.ErrNotExist}
   470			}
   471	
   472			var err error
   473			var fis []FileMetaInfo
   474	
   475			for _, rm := range roots {
   476				var fi FileMetaInfo
   477				fi, err = fs.statRoot(rm, name)
   478				if err == nil {
   479					fis = append(fis, fi)
   480				}
   481			}
   482	
   483			if fis != nil {
   484				return fis, nil
   485			}
   486	
   487			if err == nil {
   488				err = &os.PathError{Op: "LStat", Path: name, Err: err}
   489			}
   490	
   491			return nil, err
   492		}
   493	
   494		return []FileMetaInfo{newDirNameOnlyFileInfo(name, roots[0].Meta, fs.virtualDirOpener(name))}, nil
   495	}
