   511		filename = root.filename(filename)
   512		fi, err := fs.Fs.Stat(filename)
   513		if err != nil {
   514			return nil, err
   515		}
   516	
   517		var opener func() (afero.File, error)
   518		if !fi.IsDir() {
   519			// Open the file directly.
   520			// Opens the real file directly.
   521			opener = func() (afero.File, error) {
   522				return fs.Fs.Open(filename)
   523			}
   524		} else if root.Meta.Rename != nil {
   525			// A single file mount where we have mounted the containing directory.
   526			n, ok := root.Meta.Rename(fi.Name(), true)
   527			if !ok {
   528				return nil, os.ErrNotExist
   529			}
