   137					return nil
   138				}
   139				return fmt.Errorf("walk: stat: %s", err)
   140			}
   141			info = fi.(FileMetaInfo)
   142		}
   143	
   144		err := w.cfg.WalkFn(ctx, path, info)
   145		if err != nil {
   146			if info.IsDir() && err == filepath.SkipDir {
   147				return nil
   148			}
   149			return err
   150		}
