   169				if w.checkErr(path, err) {
   170					return nil
   171				}
   172				return fmt.Errorf("walk: Readdir: %w", err)
   173			}
   174	
   175			dirEntries = DirEntriesToFileMetaInfos(fis)
   176			for _, fi := range dirEntries {
   177				if fi.Meta().PathInfo == nil {
   178					fi.Meta().PathInfo = w.cfg.PathParser.Parse("", filepath.Join(pathRel, fi.Name()))
   179				}
   180			}
   181	
   182			if w.cfg.SortDirEntries {
   183				sort.Slice(dirEntries, func(i, j int) bool {
   184					return dirEntries[i].Name() < dirEntries[j].Name()
